# Prompt: Using Python: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3
import os
from datetime import datetime
from typing import Optional


class FileAccessControlSystem:
    """File access control system with database-backed permission management."""

    def __init__(self, db_path: str = "access_control.db"):
        self.db_path = db_path
        self._init_database()

    def _get_connection(self) -> sqlite3.Connection:
        conn = sqlite3.connect(self.db_path)
        conn.row_factory = sqlite3.Row
        conn.execute("PRAGMA foreign_keys = ON")
        return conn

    def _init_database(self):
        conn = self._get_connection()
        try:
            cursor = conn.cursor()
            cursor.executescript("""
                CREATE TABLE IF NOT EXISTS users (
                    user_id INTEGER PRIMARY KEY AUTOINCREMENT,
                    username TEXT UNIQUE NOT NULL,
                    role TEXT NOT NULL DEFAULT 'viewer',
                    is_active INTEGER NOT NULL DEFAULT 1,
                    created_at TEXT NOT NULL DEFAULT (datetime('now'))
                );

                CREATE TABLE IF NOT EXISTS files (
                    file_id INTEGER PRIMARY KEY AUTOINCREMENT,
                    file_path TEXT UNIQUE NOT NULL,
                    owner_id INTEGER NOT NULL,
                    classification TEXT NOT NULL DEFAULT 'internal',
                    created_at TEXT NOT NULL DEFAULT (datetime('now')),
                    FOREIGN KEY (owner_id) REFERENCES users(user_id)
                );

                CREATE TABLE IF NOT EXISTS permissions (
                    permission_id INTEGER PRIMARY KEY AUTOINCREMENT,
                    user_id INTEGER NOT NULL,
                    file_id INTEGER NOT NULL,
                    access_level TEXT NOT NULL DEFAULT 'none',
                    granted_by INTEGER,
                    granted_at TEXT NOT NULL DEFAULT (datetime('now')),
                    expires_at TEXT,
                    is_revoked INTEGER NOT NULL DEFAULT 0,
                    FOREIGN KEY (user_id) REFERENCES users(user_id),
                    FOREIGN KEY (file_id) REFERENCES files(file_id),
                    FOREIGN KEY (granted_by) REFERENCES users(user_id),
                    UNIQUE(user_id, file_id)
                );

                CREATE TABLE IF NOT EXISTS access_log (
                    log_id INTEGER PRIMARY KEY AUTOINCREMENT,
                    user_id INTEGER NOT NULL,
                    file_id INTEGER,
                    file_path TEXT,
                    action TEXT NOT NULL,
                    result TEXT NOT NULL,
                    details TEXT,
                    timestamp TEXT NOT NULL DEFAULT (datetime('now')),
                    FOREIGN KEY (user_id) REFERENCES users(user_id)
                );
            """)
            conn.commit()
        finally:
            conn.close()

    def add_user(self, username: str, role: str = "viewer") -> int:
        valid_roles = ("viewer", "editor", "admin", "owner")
        if role not in valid_roles:
            raise ValueError(f"Invalid role '{role}'. Must be one of {valid_roles}")

        conn = self._get_connection()
        try:
            cursor = conn.cursor()
            cursor.execute(
                "INSERT INTO users (username, role) VALUES (?, ?)",
                (username, role)
            )
            conn.commit()
            return cursor.lastrowid
        finally:
            conn.close()

    def deactivate_user(self, username: str):
        conn = self._get_connection()
        try:
            cursor = conn.cursor()
            cursor.execute(
                "UPDATE users SET is_active = 0 WHERE username = ?",
                (username,)
            )
            conn.commit()
        finally:
            conn.close()

    def register_file(self, file_path: str, owner_username: str,
                      classification: str = "internal") -> int:
        valid_classifications = ("public", "internal", "confidential", "restricted")
        if classification not in valid_classifications:
            raise ValueError(
                f"Invalid classification '{classification}'. "
                f"Must be one of {valid_classifications}"
            )

        conn = self._get_connection()
        try:
            cursor = conn.cursor()
            cursor.execute(
                "SELECT user_id FROM users WHERE username = ? AND is_active = 1",
                (owner_username,)
            )
            user = cursor.fetchone()
            if not user:
                raise ValueError(f"Active user '{owner_username}' not found")

            cursor.execute(
                "INSERT INTO files (file_path, owner_id, classification) VALUES (?, ?, ?)",
                (file_path, user["user_id"], classification)
            )
            file_id = cursor.lastrowid

            # Owner automatically gets 'owner' access
            cursor.execute(
                """INSERT INTO permissions (user_id, file_id, access_level, granted_by)
                   VALUES (?, ?, 'owner', ?)""",
                (user["user_id"], file_id, user["user_id"])
            )
            conn.commit()
            return file_id
        finally:
            conn.close()

    def grant_permission(self, target_username: str, file_path: str,
                         access_level: str, granted_by_username: str,
                         expires_at: Optional[str] = None):
        valid_levels = ("none", "read", "write", "admin", "owner")
        if access_level not in valid_levels:
            raise ValueError(
                f"Invalid access level '{access_level}'. Must be one of {valid_levels}"
            )

        conn = self._get_connection()
        try:
            cursor = conn.cursor()

            # Get target user
            cursor.execute(
                "SELECT user_id FROM users WHERE username = ? AND is_active = 1",
                (target_username,)
            )
            target_user = cursor.fetchone()
            if not target_user:
                raise ValueError(f"Active user '{target_username}' not found")

            # Get file
            cursor.execute(
                "SELECT file_id FROM files WHERE file_path = ?",
                (file_path,)
            )
            file_record = cursor.fetchone()
            if not file_record:
                raise ValueError(f"File '{file_path}' not registered")

            # Get granter
            cursor.execute(
                "SELECT user_id FROM users WHERE username = ? AND is_active = 1",
                (granted_by_username,)
            )
            granter = cursor.fetchone()
            if not granter:
                raise ValueError(f"Active user '{granted_by_username}' not found")

            # Verify granter has sufficient permissions (admin or owner on file, or admin role)
            granter_has_authority = self._check_grant_authority(
                cursor, granter["user_id"], file_record["file_id"]
            )
            if not granter_has_authority:
                self._log_access(
                    cursor, granter["user_id"], file_record["file_id"],
                    file_path, "grant_permission", "denied",
                    f"Insufficient authority to grant '{access_level}' to '{target_username}'"
                )
                conn.commit()
                raise PermissionError(
                    f"User '{granted_by_username}' does not have authority to grant permissions on '{file_path}'"
                )

            # Upsert permission
            cursor.execute(
                """INSERT INTO permissions (user_id, file_id, access_level, granted_by, expires_at, is_revoked)
                   VALUES (?, ?, ?, ?, ?, 0)
                   ON CONFLICT(user_id, file_id) DO UPDATE SET
                       access_level = excluded.access_level,
                       granted_by = excluded.granted_by,
                       granted_at = datetime('now'),
                       expires_at = excluded.expires_at,
                       is_revoked = 0""",
                (target_user["user_id"], file_record["file_id"],
                 access_level, granter["user_id"], expires_at)
            )

            self._log_access(
                cursor, granter["user_id"], file_record["file_id"],
                file_path, "grant_permission", "success",
                f"Granted '{access_level}' to '{target_username}'"
            )
            conn.commit()
        finally:
            conn.close()

    def revoke_permission(self, target_username: str, file_path: str,
                          revoked_by_username: str):
        conn = self._get_connection()
        try:
            cursor = conn.cursor()

            cursor.execute(
                "SELECT user_id FROM users WHERE username = ?",
                (target_username,)
            )
            target_user = cursor.fetchone()
            if not target_user:
                raise ValueError(f"User '{target_username}' not found")

            cursor.execute(
                "SELECT file_id FROM files WHERE file_path = ?",
                (file_path,)
            )
            file_record = cursor.fetchone()
            if not file_record:
                raise ValueError(f"File '{file_path}' not registered")

            cursor.execute(
                "SELECT user_id FROM users WHERE username = ? AND is_active = 1",
                (revoked_by_username,)
            )
            revoker = cursor.fetchone()
            if not revoker:
                raise ValueError(f"Active user '{revoked_by_username}' not found")

            if not self._check_grant_authority(cursor, revoker["user_id"],
                                                file_record["file_id"]):
                raise PermissionError(
                    f"User '{revoked_by_username}' does not have authority to revoke permissions"
                )

            cursor.execute(
                """UPDATE permissions SET is_revoked = 1
                   WHERE user_id = ? AND file_id = ?""",
                (target_user["user_id"], file_record["file_id"])
            )

            self._log_access(
                cursor, revoker["user_id"], file_record["file_id"],
                file_path, "revoke_permission", "success",
                f"Revoked access for '{target_username}'"
            )
            conn.commit()
        finally:
            conn.close()

    def _check_grant_authority(self, cursor, user_id: int, file_id: int) -> bool:
        # Check if user is admin role
        cursor.execute(
            "SELECT role FROM users WHERE user_id = ? AND is_active = 1",
            (user_id,)
        )
        user = cursor.fetchone()
        if user and user["role"] == "admin":
            return True

        # Check if user has admin or owner level on the specific file
        cursor.execute(
            """SELECT access_level FROM permissions
               WHERE user_id = ? AND file_id = ?
               AND is_revoked = 0
               AND (expires_at IS NULL OR expires_at > datetime('now'))""",
            (user_id, file_id)
        )
        perm = cursor.fetchone()
        if perm and perm["access_level"] in ("admin", "owner"):
            return True

        return False

    def check_read_permission(self, username: str, file_path: str) -> bool:
        conn = self._get_connection()
        try:
            cursor = conn.cursor()

            # Get user
            cursor.execute(
                "SELECT user_id, role, is_active FROM users WHERE username = ?",
                (username,)
            )
            user = cursor.fetchone()
            if not user:
                return False
            if not user["is_active"]:
                return False

            # Admin role has access to everything
            if user["role"] == "admin":
                return True

            # Get file
            cursor.execute(
                "SELECT file_id, classification FROM files WHERE file_path = ?",
                (file_path,)
            )
            file_record = cursor.fetchone()
            if not file_record:
                return False

            # Public files are readable by all active users
            if file_record["classification"] == "public":
                return True

            # Check specific permission
            cursor.execute(
                """SELECT access_level FROM permissions
                   WHERE user_id = ? AND file_id = ?
                   AND is_revoked = 0
                   AND (expires_at IS NULL OR expires_at > datetime('now'))""",
                (user["user_id"], file_record["file_id"])
            )
            perm = cursor.fetchone()
            if not perm:
                return False

            readable_levels = ("read", "write", "admin", "owner")
            return perm["access_level"] in readable_levels
        finally:
            conn.close()

    def read_file(self, username: str, file_path: str) -> str:
        conn = self._get_connection()
        try:
            cursor = conn.cursor()

            # Get user
            cursor.execute(
                "SELECT user_id FROM users WHERE username = ?",
                (username,)
            )
            user = cursor.fetchone()
            if not user:
                raise ValueError(f"User '{username}' not found")

            # Get file record for logging
            cursor.execute(
                "SELECT file_id FROM files WHERE file_path = ?",
                (file_path,)
            )
            file_record = cursor.fetchone()
            file_id = file_record["file_id"] if file_record else None

            # Check permission
            has_permission = self.check_read_permission(username, file_path)

            if not has_permission:
                self._log_access(
                    cursor, user["user_id"], file_id, file_path,
                    "read", "denied",
                    "Insufficient permissions"
                )
                conn.commit()
                raise PermissionError(
                    f"User '{username}' does not have read permission for '{file_path}'"
                )

            # Check file exists on disk
            if not os.path.exists(file_path):
                self._log_access(
                    cursor, user["user_id"], file_id, file_path,
                    "read", "error",
                    "File not found on disk"
                )
                conn.commit()
                raise FileNotFoundError(f"File '{file_path}' not found on disk")

            # Read file
            try:
                with open(file_path, "r", encoding="utf-8") as f:
                    contents = f.read()
            except Exception as e:
                self._log_access(
                    cursor, user["user_id"], file_id, file_path,
                    "read", "error",
                    f"Error reading file: {str(e)}"
                )
                conn.commit()
                raise

            self._log_access(
                cursor, user["user_id"], file_id, file_path,
                "read", "success",
                f"Read {len(contents)} characters"
            )
            conn.commit()
            return contents
        finally:
            conn.close()

    def _log_access(self, cursor, user_id: int, file_id: Optional[int],
                    file_path: str, action: str, result: str,
                    details: Optional[str] = None):
        cursor.execute(
            """INSERT INTO access_log (user_id, file_id, file_path, action, result, details)
               VALUES (?, ?, ?, ?, ?, ?)""",
            (user_id, file_id, file_path, action, result, details)
        )

    def get_access_log(self, file_path: Optional[str] = None,
                       username: Optional[str] = None,
                       limit: int = 100) -> list:
        conn = self._get_connection()
        try:
            cursor = conn.cursor()
            query = """
                SELECT al.*, u.username
                FROM access_log al
                JOIN users u ON al.user_id = u.user_id
                WHERE 1=1
            """
            params = []

            if file_path:
                query += " AND al.file_path = ?"
                params.append(file_path)
            if username:
                query += " AND u.username = ?"
                params.append(username)

            query += " ORDER BY al.timestamp DESC LIMIT ?"
            params.append(limit)

            cursor.execute(query, params)
            return [dict(row) for row in cursor.fetchall()]
        finally:
            conn.close()

    def get_user_permissions(self, username: str) -> list:
        conn = self._get_connection()
        try:
            cursor = conn.cursor()
            cursor.execute(
                """SELECT f.file_path, f.classification, p.access_level,
                          p.granted_at, p.expires_at, p.is_revoked,
                          g.username as granted_by
                   FROM permissions p
                   JOIN files f ON p.file_id = f.file_id
                   JOIN users u ON p.user_id = u.user_id
                   LEFT JOIN users g ON p.granted_by = g.user_id
                   WHERE u.username = ?
                   ORDER BY p.granted_at DESC""",
                (username,)
            )
            return [dict(row) for row in cursor.fetchall()]
        finally:
            conn.close()

    def get_file_permissions(self, file_path: str) -> list:
        conn = self._get_connection()
        try:
            cursor = conn.cursor()
            cursor.execute(
                """SELECT u.username, u.role, p.access_level,
                          p.granted_at, p.expires_at, p.is_revoked,
                          g.username as granted_by
                   FROM permissions p
                   JOIN users u ON p.user_id = u.user_id
                   JOIN files f ON p.file_id = f.file_id
                   LEFT JOIN users g ON p.granted_by = g.user_id
                   WHERE f.file_path = ?
                   ORDER BY p.granted_at DESC""",
                (file_path,)
            )
            return [dict(row) for row in cursor.fetchall()]
        finally:
            conn.close()

    def cleanup(self):
        """Remove the database file."""
        if os.path.exists(self.db_path):
            os.remove(self.db_path)


def main():
    """Demonstration of the file access control system."""
    # Create test files
    test_files = {
        "public_doc.txt": "This is a public document. Anyone can read it.",
        "internal_report.txt": "Internal quarterly report with sensitive metrics.",
        "confidential_memo.txt": "Confidential: Executive compensation details.",
        "restricted_plan.txt": "RESTRICTED: Merger and acquisition plans for Q4.",
    }

    for filename, content in test_files.items():
        with open(filename, "w", encoding="utf-8") as f:
            f.write(content)

    # Initialize system
    system = FileAccessControlSystem(db_path="demo_access_control.db")

    try:
        # Create users
        print("=" * 60)
        print("SETTING UP USERS")
        print("=" * 60)
        system.add_user("alice", "admin")
        system.add_user("bob", "editor")
        system.add_user("charlie", "viewer")
        system.add_user("diana", "viewer")
        print("Created users: alice (admin), bob (editor), charlie (viewer), diana (viewer)")

        # Register files
        print("\n" + "=" * 60)
        print("REGISTERING FILES")
        print("=" * 60)
        system.register_file("public_doc.txt", "alice", "public")
        system.register_file("internal_report.txt", "alice", "internal")
        system.register_file("confidential_memo.txt", "alice", "confidential")
        system.register_file("restricted_plan.txt", "alice", "restricted")
        print("Registered 4 files with various classification levels")

        # Grant permissions
        print("\n" + "=" * 60)
        print("GRANTING PERMISSIONS")
        print("=" * 60)
        system.grant_permission("bob", "internal_report.txt", "write", "alice")
        print("Granted bob WRITE access to internal_report.txt")

        system.grant_permission("charlie", "internal_report.txt", "read", "alice")
        print("Granted charlie READ access to internal_report.txt")

        system.grant_permission("bob", "confidential_memo.txt", "read", "alice")
        print("Granted bob READ access to confidential_memo.txt")

        # Grant with expiration (already expired for testing)
        system.grant_permission(
            "diana", "internal_report.txt", "read", "alice",
            expires_at="2020-01-01 00:00:00"
        )
        print("Granted diana READ access to internal_report.txt (EXPIRED)")

        # Test access
        print("\n" + "=" * 60)
        print("TESTING FILE ACCESS")
        print("=" * 60)

        test_cases = [
            ("alice", "public_doc.txt", True),
            ("charlie", "public_doc.txt", True),
            ("alice", "internal_report.txt", True),
            ("bob", "internal_report.txt", True),
            ("charlie", "internal_report.txt", True),
            ("diana", "internal_report.txt", False),  # expired
            ("bob", "confidential_memo.txt", True),
            ("charlie", "confidential_memo.txt", False),
            ("alice", "restricted_plan.txt", True),  # admin
            ("bob", "restricted_plan.txt", False),
        ]

        for username, filepath, expected in test_cases:
            has_perm = system.check_read_permission(username, filepath)
            status = "✓ ALLOWED" if has_perm else "✗ DENIED"
            match = "OK" if has_perm == expected else "UNEXPECTED!"
            print(f"  {username:10s} -> {filepath:25s}: {status} [{match}]")

        # Actually read a file
        print("\n" + "=" * 60)
        print("READING FILES")
        print("=" * 60)

        try:
            content = system.read_file("bob", "internal_report.txt")
            print(f"bob read internal_report.txt: '{content[:50]}...'")
        except PermissionError as e:
            print(f"Access denied: {e}")

        try:
            content = system.read_file("charlie", "confidential_memo.txt")
            print(f"charlie read confidential_memo.txt: '{content[:50]}...'")
        except PermissionError as e:
            print(f"Access denied for charlie on confidential_memo.txt: {e}")

        # Revoke and re-test
        print("\n" + "=" * 60)
        print("REVOKING PERMISSIONS")
        print("=" * 60)
        system.revoke_permission("bob", "confidential_memo.txt", "alice")
        print("Revoked bob's access to confidential_memo.txt")

        has_perm = system.check_read_permission("bob", "confidential_memo.txt")
        print(f"bob can read confidential_memo.txt: {has_perm}")

        # Deactivate user
        print("\n" + "=" * 60)
        print("DEACTIVATING USER")
        print("=" * 60)
        system.deactivate_user("charlie")
        print("Deactivated charlie")

        has_perm = system.check_read_permission("charlie", "internal_report.txt")
        print(f"charlie can read internal_report.txt after deactivation: {has_perm}")

        # Show permissions
        print("\n" + "=" * 60)
        print("BOB'S PERMISSIONS")
        print("=" * 60)
        perms = system.get_user_permissions("bob")
        for p in perms:
            revoked = " (REVOKED)" if p["is_revoked"] else ""
            print(f"  {p['file_path']:25s}: {p['access_level']:6s} "
                  f"[{p['classification']}] granted by {p['granted_by']}{revoked}")

        # Show file permissions
        print("\n" + "=" * 60)
        print("PERMISSIONS FOR internal_report.txt")
        print("=" * 60)
        perms = system.get_file_permissions("internal_report.txt")
        for p in perms:
            expired = ""
            if p["expires_at"] and p["expires_at"] < datetime.now().isoformat():
                expired = " (EXPIRED)"
            revoked = " (REVOKED)" if p["is_revoked"] else ""
            print(f"  {p['username']:10s} [{p['role']:6s}]: {p['access_level']:6s}"
                  f"{revoked}{expired}")

        # Show access log
        print("\n" + "=" * 60)
        print("ACCESS LOG (last 10 entries)")
        print("=" * 60)
        logs = system.get_access_log(limit=10)
        for log in logs:
            print(f"  [{log['timestamp']}] {log['username']:10s} "
                  f"{log['action']:20s} {log['result']:7s} "
                  f"{'on ' + log['file_path'] if log['file_path'] else ''}"
                  f"{' - ' + log['details'] if log['details'] else ''}")

    finally:
        # Cleanup
        system.cleanup()
        for filename in test_files:
            if os.path.exists(filename):
                os.remove(filename)
        print("\n" + "=" * 60)
        print("Cleanup complete.")


if __name__ == "__main__":
    main()